export interface ICorAccordionProps {
  boldHeader: TCorFontWeights;
  boldHeaderActive: TCorFontWeights;
  colorBadgeBg: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBadgeBgActive: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBadgeBorder: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBadgeBorderActive:
    | TCorBaseColorIds
    | TCorCtaColorIds
    | TCorThemesIds
    | "";
  colorBadgeText: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBadgeTextActive: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBgContent: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBgHeader: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBgHeaderActive: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBorderAcc: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorTextHeader: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorTextHeaderActive:
    | TCorBaseColorIds
    | TCorCtaColorIds
    | TCorThemesIds
    | "";
  multi: boolean;
  off: boolean;
  firstOpen: boolean;
  paddingX: Exclude<TCorSpacings, "auto">;
  paddingY: Exclude<TCorSpacings, "auto">;
  rounded: TCorRoundeds;
  shadow: TCorBoxShadows;
  sizeBorderAcc: TCorBorderSizes;
  sizeFontHeader: TCorFontSizes;
}

@Component({
  selector: "cor-accordion",
  imports: [
    // modules
    CommonModule,
  ],
  templateUrl: "./accordion.html",
  styleUrls: ["./accordion.scss"],
})
export class CorAccordionComponent {
  // inputs
  boldHeader = input<TCorFontWeights>(COR_ACCORDION_DEFAULT.boldHeader);
  boldHeaderActive = input<TCorFontWeights>(
    COR_ACCORDION_DEFAULT.boldHeaderActive,
  );
  colorBgContent = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBgContent);
  colorBgHeader = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBgHeader);
  colorBgHeaderActive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBgHeaderActive);
  colorBorderAcc = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBorderAcc);
  colorTextHeader = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorTextHeader);
  colorTextHeaderActive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorTextHeaderActive);
  colorBadgeBg = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_ACCORDION_DEFAULT.colorBadgeBg,
  );
  colorBadgeBgActive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBadgeBgActive);
  colorBadgeBorder = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBadgeBorder);
  colorBadgeBorderActive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBadgeBorderActive);
  colorBadgeText = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBadgeText);
  colorBadgeTextActive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_ACCORDION_DEFAULT.colorBadgeTextActive);
  multi = input(COR_ACCORDION_DEFAULT.multi, { transform: booleanAttribute });
  off = input(COR_ACCORDION_DEFAULT.off, { transform: booleanAttribute });
  firstOpen = input(COR_ACCORDION_DEFAULT.firstOpen, {
    transform: booleanAttribute,
  });
  paddingX = input<Exclude<TCorSpacings, "auto">>(
    COR_ACCORDION_DEFAULT.paddingX,
  );
  paddingY = input<Exclude<TCorSpacings, "auto">>(
    COR_ACCORDION_DEFAULT.paddingY,
  );
  rounded = input<TCorRoundeds>(COR_ACCORDION_DEFAULT.rounded);
  shadow = input<TCorBoxShadows>(COR_ACCORDION_DEFAULT.shadow);
  sizeBorderAcc = input<TCorBorderSizes>(COR_ACCORDION_DEFAULT.sizeBorderAcc);
  sizeFontHeader = input<TCorFontSizes>(COR_ACCORDION_DEFAULT.sizeFontHeader);

  // publics - styles
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const boldHeader: TCorFontWeights = this.boldHeader();
    const boldHeaderActive: TCorFontWeights = this.boldHeaderActive();
    const colorBorderAcc:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBorderAcc();
    const colorBgHeader:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBgHeader();
    const colorBgHeaderActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBgHeaderActive();
    const colorTextHeader:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorTextHeader();
    const colorTextHeaderActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorTextHeaderActive();

    const colorBadgeBg = this.colorBadgeBg();
    const colorBadgeBgActive = this.colorBadgeBgActive();
    const colorBadgeBorder = this.colorBadgeBorder();
    const colorBadgeBorderActive = this.colorBadgeBorderActive();
    const colorBadgeText = this.colorBadgeText();
    const colorBadgeTextActive = this.colorBadgeTextActive();

    const colorBadgeBgVal: string = !!colorBadgeBg
      ? cssVar(`--clr-${colorBadgeBg}`)
      : "transparent";
    const colorBadgeBgActiveVal: string = !!colorBadgeBgActive
      ? cssVar(`--clr-${colorBadgeBgActive}`)
      : "transparent";
    const colorBadgeBorderVal: string = !!colorBadgeBorder
      ? cssVar(`--clr-${colorBadgeBorder}`)
      : "transparent";
    const colorBadgeBorderActiveVal: string = !!colorBadgeBorderActive
      ? cssVar(`--clr-${colorBadgeBorderActive}`)
      : "transparent";
    const colorBadgeTextVal: string = !!colorBadgeText
      ? cssVar(`--clr-${colorBadgeText}`)
      : "transparent";
    const colorBadgeTextActiveVal: string = !!colorBadgeTextActive
      ? cssVar(`--clr-${colorBadgeTextActive}`)
      : "transparent";

    const paddingX: Exclude<TCorSpacings, "auto"> = this.paddingX();
    const paddingY: Exclude<TCorSpacings, "auto"> = this.paddingY();
    const rounded: TCorRoundeds = this.rounded();
    const sizeBorderAcc: TCorBorderSizes = this.sizeBorderAcc();
    const sizeFontHeader: TCorFontSizes = this.sizeFontHeader();

    const boldHeaderVal: number = COR_FONT_WEIGHTS?.[boldHeader];
    const boldHeaderActiveVal: number = COR_FONT_WEIGHTS?.[boldHeaderActive];
    const colorBorderAccVal: string = !!colorBorderAcc
      ? cssVar(`--clr-${colorBorderAcc}`)
      : "transparent";
    const colorBgHeaderVal: string = !!colorBgHeader
      ? cssVar(`--clr-${colorBgHeader}`)
      : "transparent";
    const colorBgHeaderActiveVal: string = !!colorBgHeaderActive
      ? cssVar(`--clr-${colorBgHeaderActive}`)
      : "transparent";
    const colorTextHeaderVal: string = !!colorTextHeader
      ? cssVar(`--clr-${colorTextHeader}`)
      : "transparent";
    const colorTextHeaderActiveVal: string = !!colorTextHeaderActive
      ? cssVar(`--clr-${colorTextHeaderActive}`)
      : "transparent";

    const paddingXVal: number = COR_PADDINGS?.[paddingX];
    const paddingYVal: number = COR_PADDINGS?.[paddingY];
    const roundedVal: number = COR_ROUNDEDS?.[rounded];
    const sizeBorderAccVal: number = COR_BORDER_SIZES?.[sizeBorderAcc];
    const sizeFontHeaderVal: number = COR_FONT_SIZES?.[sizeFontHeader];

    return `
    --cor-accordion-clr-bg-header: ${colorBgHeaderVal};
    --cor-accordion-clr-bg-header-active: ${colorBgHeaderActiveVal};
    --cor-accordion-clr-text-header: ${colorTextHeaderVal};
    --cor-accordion-clr-text-header-active: ${colorTextHeaderActiveVal};
    --cor-accordion-clr-border-acc: ${colorBorderAccVal};
    --cor-accordion-clr-badge-bg: ${colorBadgeBgVal};
    --cor-accordion-clr-badge-bg-active: ${colorBadgeBgActiveVal};
    --cor-accordion-clr-badge-border: ${colorBadgeBorderVal};
    --cor-accordion-clr-badge-border-active: ${colorBadgeBorderActiveVal};
    --cor-accordion-clr-badge-text: ${colorBadgeTextVal};
    --cor-accordion-clr-badge-text-active: ${colorBadgeTextActiveVal};
    --cor-accordion-bold-header: ${boldHeaderVal};
    --cor-accordion-bold-header-active: ${boldHeaderActiveVal};
    --cor-accordion-padding-y: ${paddingYVal}rem;
    --cor-accordion-padding-x: ${paddingXVal}rem;
    --cor-accordion-rounded: ${roundedVal}rem;
    --cor-accordion-size-font-header: ${sizeFontHeaderVal}rem;
    --cor-accordion-size-border-acc: ${sizeBorderAccVal}px;
  `
      .trim()
      .replace(/\n/g, "");
  });

  // publics
  openIds = signal<(string | number)[]>([]);

  // privates
  private readonly userInteracted = signal<boolean>(false);
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );
  private readonly panels = contentChildren(CorAccordionPanelComponent);

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor

  // constructor
  constructor() {
    effect(() => {
      const panels = this.panels() || [];

      panels.forEach((panel: CorAccordionPanelComponent, i: number) => {
        const isSolo: boolean = panels.length === 1;
        const isFirst: boolean = i === 0;
        const isLast: boolean = i === panels.length - 1;

        panel._position.set(
          isSolo ? "solo" : isFirst ? "first" : isLast ? "last" : "middle",
        );
      });
    });

    effect(() => {
      const firstOpen = this.firstOpen();
      const panels = this.panels();
      const firstId = panels?.[0]?.id();

      if (this.userInteracted()) return; // user has taken over — firstOpen no longer applies

      this.openIds.set(firstOpen && firstId !== undefined ? [firstId] : []);
    });
  }

  // lifecycles
  // ngOnInit() {
  //   if (!!this.firstOpen()) {
  //     this.openIds.set([this.panels()?.[0]?.id()]);
  //   }
  // }

  // functions
  handleToggle(id: string | number) {
    this.userInteracted.set(true); // from now on, firstOpen is ignored

    const current: (string | number)[] = this.openIds();
    const isOpen = current.includes(id);

    if (this.multi()) {
      this.openIds.set(
        isOpen ? current.filter((i) => i !== id) : [...current, id],
      );
    } else {
      this.openIds.set(isOpen ? [] : [id]);
    }
  }
}

@Component({
  selector: "cor-accordion-panel",
  imports: [
    // modules
    CommonModule,
  ],
  templateUrl: "./accordion-panel.html",
  styleUrls: ["./accordion-panel.scss"],
  host: {
    "[attr.data-position]": "_position()",
    "[class.--solo]": '_position() === "solo"',
    "[class.--first]": '_position() === "first"',
    "[class.--middle]": '_position() === "middle"',
    "[class.--last]": '_position() === "last"',
  },
})
export class CorAccordionPanelComponent {
  // inputs
  caption1 = input<string>("");
  caption2 = input<string>("");
  badge1 = input<any>(null);
  badge2 = input<any>(null);
  id = input<string | number>(randomStr());
  colorBgContent = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >("");

  // publics - styles
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const colorBgContent:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBgContent() || this.colorBgContentDef();

    const colorBgContentVal: string = !!colorBgContent
      ? cssVar(`--clr-${colorBgContent}`)
      : "transparent";

    return `
        --cor-accordion-clr-bg-content: ${colorBgContentVal};
  `
      .trim()
      .replace("\n", "");
  });

  // publics - inherited
  colorBgContentDef = computed<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(() => this.accordion.colorBgContent());
  // dark = computed<boolean>(() => this.accordion.dark());
  isExpanded = computed<boolean>(() =>
    this.accordion.openIds().includes(this.id()),
  );
  readonly _position = signal<TAccordionPosition>("solo");

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  private accordion = inject(CorAccordionComponent);
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // functions
  toggle() {
    this.accordion.handleToggle(this.id());
  }
}

export const COR_ANIMATED_PANEL_DIRECTION = [
  "left",
  "top",
  "right",
  "bottom",
] as const;

export interface ICorAnimatedPanelProps {
  colorA: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorB: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  direction: TCorAnimatedPanelDirection;
  effect: TCorAnimatedPanelEffects;
  grained: boolean;
  intensity: TCorAnimatedPanelIntensity;
  opacityGrain: TCorOpacities;
  overflowed: boolean;
  rounded: TCorRoundeds;
  shadow: TCorBoxShadows;
  speed: number;
  swapColors: boolean;
}

@Component({
  selector: "cor-animated-panel",
  imports: [
    // modules
    CommonModule,
  ],
  templateUrl: "./animated-panel.html",
  styleUrl: "./animated-panel.scss",
})
export class CorAnimatedPanelComponent {
  // inputs
  // colorA = input('#1a3aff');
  // colorB = input('#e6a817');
  colorA = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_ANIMATED_PANEL_DEFAULT.colorA,
  );
  colorB = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_ANIMATED_PANEL_DEFAULT.colorB,
  );
  direction = input<TCorAnimatedPanelDirection>(
    COR_ANIMATED_PANEL_DEFAULT.direction,
  );
  effect = input<TCorAnimatedPanelEffects>(COR_ANIMATED_PANEL_DEFAULT.effect);
  grained = input(COR_ANIMATED_PANEL_DEFAULT.grained, {
    transform: booleanAttribute,
  });
  intensity = input<TCorAnimatedPanelIntensity>(
    COR_ANIMATED_PANEL_DEFAULT.intensity,
  );
  opacityGrain = input<TCorOpacities>(COR_ANIMATED_PANEL_DEFAULT.opacityGrain);
  overflowed = input(COR_ANIMATED_PANEL_DEFAULT.overflowed, {
    transform: booleanAttribute,
  });
  rounded = input<TCorRoundeds>(COR_ANIMATED_PANEL_DEFAULT.rounded);
  shadow = input<TCorBoxShadows>(COR_ANIMATED_PANEL_DEFAULT.shadow);
  speed = input<number>(COR_ANIMATED_PANEL_DEFAULT.speed);
  swapColors = input(COR_ANIMATED_PANEL_DEFAULT.swapColors, {
    transform: booleanAttribute,
  });

  colorARgb = computed<TCorRgb>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const swapColors: boolean = this.swapColors();
    const colorA: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorA();
    const colorB: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorB();
    return hslStrToRgb(cssVar(`--clr-${!swapColors ? colorA : colorB}`));
  });
  colorBRgb = computed<TCorRgb>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const swapColors: boolean = this.swapColors();
    const colorA: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorA();
    const colorB: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorB();
    return hslStrToRgb(cssVar(`--clr-${!swapColors ? colorB : colorA}`));
  });

  // ── Signal queries ──────────────────────────────────────────────────────────
  private readonly panelRef =
    viewChild.required<ElementRef<HTMLDivElement>>("panelRef");
  private readonly canvasRef =
    viewChild.required<ElementRef<HTMLCanvasElement>>("canvasRef");
  private readonly grainRef =
    viewChild<ElementRef<HTMLCanvasElement>>("grainRef");

  // ── Private state ───────────────────────────────────────────────────────────
  private readonly _isBrowser = isPlatformBrowser(inject(PLATFORM_ID));
  private _raf = 0;
  private _grainRaf = 0;
  private _t = 0;

  private _pts: IAnimatedPanelParticleEffect[] | null = null;
  private _drops: IAnimatedPanelDropEffect[] | null = null;
  private _puddles: IAnimatedPanelPuddleEffect[] | null = null;
  private _debris: IAnimatedPanelCosmosDebrisEffect[] | null = null;

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    // Clear animation pools whenever the effect changes
    // effect(
    //   () => { this.effect(); this.#clearPools(); }
    // );

    effect(() => {
      this.effect();
      this.intensity();
      this.#clearPools();
    });

    // Start/stop grain loop reactively
    effect(() => {
      if (!this._isBrowser) return;
      if (!this.grained()) {
        cancelAnimationFrame(this._grainRaf);
        this._grainRaf = 0;
      } else {
        queueMicrotask(() => this.#tickGrain());
      }
    });

    // Kick off the main loop after the first render
    afterNextRender(() => {
      if (!this._isBrowser) return;
      this.#resize();
      this.#loop();
      if (this.grained()) queueMicrotask(() => this.#tickGrain());
    });
  }
  // lifecycles
  ngOnDestroy(): void {
    cancelAnimationFrame(this._raf);
    cancelAnimationFrame(this._grainRaf);
  }

  // ── Render loop ──────────────────────────────────────────────────────────────

  #loop(): void {
    const canvas = this.canvasRef().nativeElement;
    const panel = this.panelRef().nativeElement;
    if (
      canvas.width !== panel.offsetWidth ||
      canvas.height !== panel.offsetHeight
    ) {
      this.#resize();
    }
    this._t += 0.016;
    this.#draw(canvas);
    this._raf = requestAnimationFrame(() => this.#loop());
  }

  #resize(): void {
    const c = this.canvasRef().nativeElement;
    const p = this.panelRef().nativeElement;
    c.width = p.offsetWidth;
    c.height = p.offsetHeight;
  }

  #draw(canvas: HTMLCanvasElement): void {
    switch (this.effect()) {
      case "orbs":
        this.#orbs(canvas);
        break;
      case "plasma":
        this.#plasma(canvas);
        break;
      case "aurora":
        this.#aurora(canvas);
        break;
      case "particles":
        this.#particles(canvas);
        break;
      case "rainy":
        this.#rainy(canvas);
        break;
      case "cosmos":
        this.#cosmos(canvas);
        break;
    }
  }

  // ── Effect: Orbs ─────────────────────────────────────────────────────────────

  #orbs(canvas: HTMLCanvasElement): void {
    const ctx = canvas.getContext("2d")!;
    const { w, h, A, B, sc } = this.#canvas(canvas, 0.004);
    paintBg(ctx, w, h);
    const M = lerp(A, B, 0.5);
    [
      {
        px: 0.15 + 0.1 * Math.sin(this._t * sc * 45),
        py: 0.2 + 0.12 * Math.cos(this._t * sc * 32),
        r: 0.55,
        c: A,
        a: 0.55,
      },
      {
        px: 0.82 + 0.08 * Math.cos(this._t * sc * 38),
        py: 0.75 + 0.1 * Math.sin(this._t * sc * 26),
        r: 0.5,
        c: B,
        a: 0.5,
      },
      {
        px: 0.5 + 0.15 * Math.sin(this._t * sc * 58),
        py: 0.45 + 0.1 * Math.cos(this._t * sc * 51),
        r: 0.35,
        c: M,
        a: 0.35,
      },
      {
        px: 0.75 + 0.06 * Math.sin(this._t * sc * 32),
        py: 0.15 + 0.08 * Math.cos(this._t * sc * 71),
        r: 0.22,
        c: B,
        a: 0.28,
      },
    ].forEach((o) => {
      const gx = o.px * w,
        gy = o.py * h,
        gr = Math.max(w, h) * o.r;
      const g = ctx.createRadialGradient(gx, gy, 0, gx, gy, gr);
      g.addColorStop(0, rgb2rgba(o.c, o.a));
      g.addColorStop(1, rgb2rgba(o.c, 0));
      ctx.fillStyle = g;
      ctx.fillRect(0, 0, w, h);
    });
  }

  // ── Effect: Plasma ───────────────────────────────────────────────────────────

  #plasma(canvas: HTMLCanvasElement): void {
    const ctx = canvas.getContext("2d")!;
    const { w, h, A, B, sc } = this.#canvas(canvas, 0.003);
    const img = ctx.createImageData(w, h);
    const d = img.data;
    for (let y = 0; y < h; y += 2) {
      for (let px = 0; px < w; px += 2) {
        const nx = px / w,
          ny = y / h;
        const v =
          Math.sin(nx * 8 + this._t * sc * 40) +
          Math.sin(ny * 6 - this._t * sc * 30) +
          Math.sin((nx + ny) * 5 + this._t * sc * 25) +
          Math.sin(
            Math.sqrt((nx - 0.5) ** 2 + (ny - 0.5) ** 2) * 10 -
              this._t * sc * 35,
          );
        const n = (v + 4) / 8;
        const wv = Math.sin(n * Math.PI);
        const col = lerp(A, B, n);
        const dk =
          Math.pow(Math.min(nx, 1 - nx) * 2, 0.3) *
          Math.pow(Math.min(ny, 1 - ny) * 2, 0.3);
        const br = Math.round(wv * 180 * dk + 20);
        for (let dy = 0; dy < 2 && y + dy < h; dy++) {
          for (let dx = 0; dx < 2 && px + dx < w; dx++) {
            const i = ((y + dy) * w + (px + dx)) * 4;
            d[i] = Math.min(255, (col[0] * br) / 180);
            d[i + 1] = Math.min(255, (col[1] * br) / 180);
            d[i + 2] = Math.min(255, (col[2] * br) / 180);
            d[i + 3] = 255;
          }
        }
      }
    }
    ctx.putImageData(img, 0, 0);
  }

  // ── Effect: Aurora ───────────────────────────────────────────────────────────

  #aurora(canvas: HTMLCanvasElement): void {
    const ctx = canvas.getContext("2d")!;
    const { w, h, A, B, sc } = this.#canvas(canvas, 0.006);
    paintBg(ctx, w, h);
    for (let i = 0; i < 6; i++) {
      const ph = i / 6;
      const yb = h * (0.1 + ph * 0.8);
      const amp = h * 0.18 * Math.sin(this._t * sc * 2 + ph * 4);
      ctx.beginPath();
      for (let px = 0; px <= w; px += 4) {
        const y =
          yb +
          amp *
            Math.sin(
              (px / w) * (3 + i * 0.5) * Math.PI * 2 +
                this._t * sc * 3 +
                ph * 5,
            );
        px === 0 ? ctx.moveTo(px, y) : ctx.lineTo(px, y);
      }
      ctx.lineTo(w, h);
      ctx.lineTo(0, h);
      ctx.closePath();
      ctx.fillStyle = rgb2rgba(
        lerp(A, B, ph),
        0.08 + 0.06 * Math.sin(this._t * sc * 1.5 + ph * 3),
      );
      ctx.fill();
    }
    const g = ctx.createRadialGradient(
      w * 0.3,
      h * 0.3,
      0,
      w * 0.3,
      h * 0.3,
      w * 0.7,
    );
    g.addColorStop(0, rgb2rgba(A, 0.12));
    g.addColorStop(1, rgb2rgba(A, 0));
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, w, h);
  }

  // ── Effect: Particles ────────────────────────────────────────────────────────
  #particles(canvas: HTMLCanvasElement): void {
    const ctx = canvas.getContext("2d")!;
    const { w, h, A, B, sc, dir, intens } = this.#canvas(canvas, 0.003);

    const countMap = { low: 60, medium: 120, high: 220 } as const;
    const count = countMap[intens];

    paintBg(ctx, w, h);

    if (!this._pts || this._pts.length !== count) {
      this._pts = Array.from({ length: count }, () => this.#spawnParticle(dir));
    }

    this._pts.forEach((p) => {
      p.px += p.vx * (1 + sc * 3);
      p.py += p.vy * (1 + sc * 3);
      p.life += 0.003 * (1 + sc * 2);

      const oob =
        (dir === "bottom" && (p.py < -0.05 || p.px < -0.1 || p.px > 1.1)) ||
        (dir === "top" && (p.py > 1.05 || p.px < -0.1 || p.px > 1.1)) ||
        (dir === "left" && (p.px > 1.05 || p.py < -0.1 || p.py > 1.1)) ||
        (dir === "right" && (p.px < -0.05 || p.py < -0.1 || p.py > 1.1)) ||
        p.life > 1;

      if (oob) Object.assign(p, this.#spawnParticle(dir));

      const alphaMult = intens === "low" ? 0.6 : intens === "high" ? 1.0 : 0.8;
      const sizeMult = intens === "low" ? 0.7 : intens === "high" ? 1.4 : 1.0;

      const col = lerp(A, B, p.r);
      const al = (1 - p.life) * (0.6 + 0.4 * p.r) * alphaMult;
      const ex = p.px * w,
        ey = p.py * h;
      const gs = p.sz * 3 * sizeMult;

      const g = ctx.createRadialGradient(ex, ey, 0, ex, ey, gs);
      g.addColorStop(0, rgb2rgba(col, al));
      g.addColorStop(1, rgb2rgba(col, 0));
      ctx.fillStyle = g;
      ctx.beginPath();
      ctx.arc(ex, ey, gs, 0, Math.PI * 2);
      ctx.fill();
    });

    const gd = ctx.createLinearGradient(0, h * 0.6, 0, h);
    gd.addColorStop(0, rgb2rgba([7, 10, 24], 0));
    gd.addColorStop(1, rgb2rgba([7, 10, 24], 0.9));
    ctx.fillStyle = gd;
    ctx.fillRect(0, 0, w, h);
  }

  // ── Effect: Rainy ────────────────────────────────────────────────────────────

  #rainy(canvas: HTMLCanvasElement): void {
    const ctx = canvas.getContext("2d")!;
    const { w, h, A, B, sc } = this.#canvas(canvas, 0.004);
    paintBg(ctx, w, h);
    if (!this._drops) {
      this._drops = Array.from({ length: 200 }, () => ({
        px: Math.random(),
        py: Math.random(),
        spd: 0.004 + Math.random() * 0.009,
        len: 0.03 + Math.random() * 0.05,
        al: 0.15 + Math.random() * 0.4,
        col: Math.random(),
        wd: 0.4 + Math.random() * 0.8,
      }));
    }
    if (!this._puddles) {
      this._puddles = Array.from({ length: 6 }, (_, i) => ({
        px: 0.08 + i * 0.16,
        ph: i * 0.8,
        spd: 0.5 + Math.random() * 0.6,
      }));
    }
    const wa = 0.22 + 0.06 * Math.sin(this._t * sc * 3);
    const sky = ctx.createLinearGradient(0, 0, 0, h);
    sky.addColorStop(0, rgb2rgba(lerp(A, B, 0.2), 0.35));
    sky.addColorStop(0.6, rgb2rgba(A, 0.1));
    sky.addColorStop(1, rgb2rgba([7, 10, 24], 0.4));
    ctx.fillStyle = sky;
    ctx.fillRect(0, 0, w, h);
    [0.15, 0.32, 0.5].forEach((band, i) => {
      const my = h * (band + 0.04 * Math.sin(this._t * sc * 2 + i));
      const mg = ctx.createLinearGradient(0, my - h * 0.08, 0, my + h * 0.1);
      const mc = lerp(A, B, band);
      mg.addColorStop(0, rgb2rgba(mc, 0));
      mg.addColorStop(
        0.5,
        rgb2rgba(mc, 0.07 + 0.03 * Math.sin(this._t * sc * 3 + i)),
      );
      mg.addColorStop(1, rgb2rgba(mc, 0));
      ctx.fillStyle = mg;
      ctx.fillRect(0, my - h * 0.08, w, h * 0.18);
    });
    ctx.save();
    this._drops.forEach((d) => {
      d.py += d.spd * (1 + sc * 3);
      if (d.py > 1.05) d.py = -0.05 + Math.random() * 0.05;
      const ex = d.px * w,
        ey = d.py * h;
      const ex2 = ex + Math.sin(wa) * d.len * h;
      const ey2 = ey + Math.cos(wa) * d.len * h;
      const col = lerp(A, B, d.col);
      const lg = ctx.createLinearGradient(ex, ey, ex2, ey2);
      lg.addColorStop(0, rgb2rgba(col, 0));
      lg.addColorStop(0.3, rgb2rgba(col, d.al));
      lg.addColorStop(1, rgb2rgba(col, d.al * 0.2));
      ctx.strokeStyle = lg;
      ctx.lineWidth = d.wd;
      ctx.beginPath();
      ctx.moveTo(ex, ey);
      ctx.lineTo(ex2, ey2);
      ctx.stroke();
    });
    ctx.restore();
    this._puddles.forEach((p) => {
      for (let ring = 0; ring < 3; ring++) {
        const rph = (this._t * sc * p.spd * 2 + p.ph + ring * 0.33) % 1;
        const rad = (28 + ring * 16) * rph;
        const al = (1 - rph) * 0.18;
        ctx.beginPath();
        ctx.ellipse(p.px * w, h * 0.92, rad, rad * 0.25, 0, 0, Math.PI * 2);
        ctx.strokeStyle = rgb2rgba(lerp(A, B, p.px), al);
        ctx.lineWidth = 1;
        ctx.stroke();
      }
    });
    const vg = ctx.createRadialGradient(
      w / 2,
      h / 2,
      h * 0.2,
      w / 2,
      h / 2,
      Math.max(w, h) * 0.75,
    );
    vg.addColorStop(0, rgb2rgba([7, 10, 24], 0));
    vg.addColorStop(1, rgb2rgba([7, 10, 24], 0.55));
    ctx.fillStyle = vg;
    ctx.fillRect(0, 0, w, h);
  }

  // ── Effect: Cosmos ────────────────────────────────────────────────────────────
  #cosmos(canvas: HTMLCanvasElement): void {
    const ctx = canvas.getContext("2d")!;
    const { w, h, A, B, sc, dir, intens } = this.#canvas(canvas, 0.004);

    const countMap = { low: 40, medium: 80, high: 140 } as const;
    const trailMap = { low: 0.5, medium: 1.0, high: 2.0 } as const;
    const count = countMap[intens];
    const trailMult = trailMap[intens];

    paintBg(ctx, w, h);

    if (!this._debris || this._debris.length !== count) {
      this._debris = Array.from({ length: count }, () =>
        this.#spawnDebris(dir),
      );
    }

    // Sweep gradient axis follows direction
    const isVertical = dir === "top" || dir === "bottom";
    const sw = (this._t * sc * 8) % 2;
    const bgg = isVertical
      ? ctx.createLinearGradient(0, h * (sw - 0.8), 0, h * (sw + 0.2))
      : ctx.createLinearGradient(w * (sw - 0.8), 0, w * (sw + 0.2), h);
    bgg.addColorStop(0, rgb2rgba(A, 0));
    bgg.addColorStop(0.3, rgb2rgba(A, 0.18));
    bgg.addColorStop(0.55, rgb2rgba(lerp(A, B, 0.5), 0.12));
    bgg.addColorStop(0.8, rgb2rgba(B, 0.18));
    bgg.addColorStop(1, rgb2rgba(B, 0));
    ctx.fillStyle = bgg;
    ctx.fillRect(0, 0, w, h);

    ctx.save();
    ctx.globalCompositeOperation = "screen";

    this._debris.forEach((d) => {
      const gust = 1 + 0.7 * Math.sin(this._t * sc * 5 + d.ph);
      const dvx = d.vx * gust * (1 + sc * 3);
      const dvy = d.vy + 0.001 * Math.sin(this._t * sc * 8 + d.ph * 2);

      d.px += dvx;
      d.py += dvy;

      // Wrap on the correct axis per direction
      const oob =
        (dir === "right" && d.px > 1.08) ||
        (dir === "left" && d.px < -0.08) ||
        (dir === "bottom" && d.py > 1.08) ||
        (dir === "top" && d.py < -0.08);

      if (oob) Object.assign(d, this.#spawnDebris(dir));

      const ex = d.px * w,
        ey = d.py * h;
      const col = lerp(A, B, d.col);
      const fl = d.al * (0.6 + 0.4 * Math.sin(this._t * sc * 12 + d.ph));

      const gr = ctx.createRadialGradient(ex, ey, 0, ex, ey, d.sz * 4);
      gr.addColorStop(0, rgb2rgba(col, fl));
      gr.addColorStop(1, rgb2rgba(col, 0));
      ctx.fillStyle = gr;
      ctx.beginPath();
      ctx.arc(ex, ey, d.sz * 4, 0, Math.PI * 2);
      ctx.fill();

      // Trail drawn backwards along actual velocity vector
      const trailX = ex - dvx * w * 6 * trailMult;
      const trailY = ey - dvy * h * 6 * trailMult;
      ctx.beginPath();
      ctx.moveTo(ex, ey);
      ctx.lineTo(trailX, trailY);
      ctx.strokeStyle = rgb2rgba(col, fl * 0.4);
      ctx.lineWidth = d.sz * 0.5;
      ctx.stroke();
    });

    ctx.restore();

    const vg = ctx.createRadialGradient(
      w / 2,
      h / 2,
      h * 0.15,
      w / 2,
      h / 2,
      Math.max(w, h) * 0.8,
    );
    vg.addColorStop(0, rgb2rgba([7, 10, 24], 0));
    vg.addColorStop(1, rgb2rgba([7, 10, 24], 0.5));
    ctx.fillStyle = vg;
    ctx.fillRect(0, 0, w, h);
  }

  // ── Grain overlay ────────────────────────────────────────────────────────────

  #tickGrain(): void {
    const grainEl = this.grainRef();
    if (!grainEl || !this.grained()) return;
    const c = grainEl.nativeElement;
    const p = this.panelRef().nativeElement;
    c.width = p.offsetWidth;
    c.height = p.offsetHeight;
    const ctx = c.getContext("2d")!;
    const img = ctx.createImageData(c.width, c.height);
    const d = img.data;
    for (let i = 0; i < d.length; i += 4) {
      const v = (Math.random() - 0.5) * 90;
      d[i] = d[i + 1] = d[i + 2] = 128 + v;
      d[i + 3] = 255;
    }
    ctx.putImageData(img, 0, 0);
    this._grainRaf = requestAnimationFrame(() => this.#tickGrain());
  }

  // ── Private helpers ──────────────────────────────────────────────────────────

  #clearPools(): void {
    this._pts = null;
    this._drops = null;
    this._puddles = null;
    this._debris = null;
  }

  #canvas(
    canvas: HTMLCanvasElement,
    spdScale: number,
  ): TCorAnimatedPanelCanvasConfig {
    return {
      w: canvas.width,
      h: canvas.height,
      A: this.colorARgb(),
      B: this.colorBRgb(),
      sc: this.speed() * spdScale,
      dir: this.direction(),
      intens: this.intensity(),
    };
  }

  #spawnParticle(
    dir: TCorAnimatedPanelDirection,
  ): IAnimatedPanelParticleEffect {
    const spd = 0.0004 + Math.random() * 0.001;
    const drift = (Math.random() - 0.5) * 0.0004;
    const [px, py, vx, vy] =
      dir === "bottom"
        ? [Math.random(), 1.05, drift, -spd]
        : dir === "top"
          ? [Math.random(), -0.05, drift, spd]
          : dir === "left"
            ? [-0.05, Math.random(), spd, drift]
            : [1.05, Math.random(), -spd, drift];
    return {
      px,
      py,
      vx,
      vy,
      r: Math.random(),
      life: Math.random() * 0.3,
      sz: 1 + Math.random() * 3,
    };
  }
  #spawnDebris(
    dir: TCorAnimatedPanelDirection,
  ): IAnimatedPanelCosmosDebrisEffect {
    const spd = 0.003 + Math.random() * 0.014;
    const drift = (Math.random() - 0.5) * 0.003;
    const [px, py, vx, vy] =
      dir === "right"
        ? [Math.random(), Math.random(), spd, drift]
        : dir === "left"
          ? [Math.random(), Math.random(), -spd, drift]
          : dir === "bottom"
            ? [Math.random(), Math.random(), drift, spd]
            : [Math.random(), Math.random(), drift, -spd];
    return {
      px,
      py,
      vx,
      vy,
      ph: Math.random() * Math.PI * 2,
      sz: 0.6 + Math.random() * 3,
      col: Math.random(),
      al: 0.2 + Math.random() * 0.55,
    };
  }

  // private _c(canvas: HTMLCanvasElement, spdScale: number) {
  //   return {
  //     w: canvas.width,
  //     h: canvas.height,
  //     A: hexToRgb(this.colorA()),
  //     B: hexToRgb(this.colorB()),
  //     sc: this.speed() * spdScale,
  //   };
  // }
}

