  shadow = input<TCorBoxShadows>(COR_BTN_DEFAULT.shadow);
  sizeBorder = input<TCorBorderSizes>(COR_BTN_DEFAULT.sizeBorder);
  sizeFont = input<TCorFontSizes>(COR_BTN_DEFAULT.sizeFont);
  tracking = input<TCorLetterSpacings>(COR_BTN_DEFAULT.tracking);
  // bgCustomColor = input<string>(COR_BTN_DEFAULT.bgCustomColor);

  // publics - styles
