    const isDarkMode: boolean = this.isDarkMode();
    const sizeBorder: TCorBorderSizes = this.sizeBorder();
    const sizeFont: TCorFontSizes = this.sizeFont();
    const colorBg: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorBg();
    const colorBgHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBgHover();
    const colorText: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorText();
    const colorTextHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorTextHover();
    const opacityColorBg: TCorOpacities = this.opacityColorBg();
    const rounded: TCorRoundeds = this.rounded();

    // vals
    const colorBgHoverVal: string = !!colorBgHover
      ? cssVar(`--clr-${colorBgHover}`)
      : "transparent";
    // const colorBgVal: string = !!colorBg ? cssVar(`--clr-${colorBg}`) : 'transparent';
    const colorBgVal: string = !!colorBg
      ? hslStrToRgba(cssVar(`--clr-${colorBg}`), opacityColorBg / 100)
      : "transparent";
    const colorBgO100Val: string = !!colorBg
      ? cssVar(`--clr-${colorBg}`)
      : "transparent";
    const colorTextVal: string = !!colorText
      ? cssVar(`--clr-${colorText}`)
      : "transparent";
    const colorTextHoverVal: string = !!colorTextHover
      ? cssVar(`--clr-${colorTextHover}`)
      : "transparent";
    // const colorTextInvertVal: string = !!colorText ? cssVar(`--clr-${colorText}`) : 'transparent';
    const sizeBorderVal: number = COR_BORDER_SIZES?.[sizeBorder];
    const sizeFontVal: number = COR_FONT_SIZES?.[sizeFont];
    const roundedVal: number = COR_ROUNDEDS?.[rounded];
    // --cor-btn-clr-text-invert: ${colorTextInvertVal};

    return `
--cor-btn-clr-bg: ${colorBgVal};
--cor-btn-clr-bg-o-100: ${colorBgO100Val};
--cor-btn-clr-bg-hover: ${colorBgHoverVal};
--cor-btn-clr-text: ${colorTextVal};
--cor-btn-clr-text-hover: ${colorTextHoverVal};
--cor-btn-size-border: ${sizeBorderVal}px;
--cor-btn-size-font: ${sizeFontVal}rem;
--cor-btn-rounded: ${roundedVal}rem;
`
      .trim()
      .replace("\n", "");
  });

  // publics
  hovered = signal<boolean>(false);

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);
}

