@Component({
  selector: "cor-circular-text",
  imports: [
    // modules
    CommonModule,
  ],
  templateUrl: "./circular-text.html",
  styleUrl: "./circular-text.scss",
})
export class CorCircularTextComponent {
  // viewChilds
  svgEl = viewChild<ElementRef<SVGElement>>("svgEl");

  // inputs
  bold = input<TCorFontWeights>(COR_CIRCULAR_TEXT_DEFAULT.bold);
  clockwise = input(COR_CIRCULAR_TEXT_DEFAULT.clockwise, {
    transform: booleanAttribute,
  });
  color = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_CIRCULAR_TEXT_DEFAULT.color,
  );
  // dark = input(COR_CIRCULAR_TEXT_DEFAULT.dark, { transform: booleanAttribute });
  duration = input<number>(COR_CIRCULAR_TEXT_DEFAULT.duration);
  // fontFamily = input<string>(COR_CIRCULAR_TEXT_DEFAULT.fontFamily);
  fontSizePx = input<number>(COR_CIRCULAR_TEXT_DEFAULT.fontSizePx);
  letterSpacingPx = input<number>(COR_CIRCULAR_TEXT_DEFAULT.letterSpacingPx);
  opacity = input<TCorOpacities>(COR_CIRCULAR_TEXT_DEFAULT?.opacity);
  separator = input<string>(COR_CIRCULAR_TEXT_DEFAULT.separator);
  sizePx = input<number>(COR_CIRCULAR_TEXT_DEFAULT.sizePx);
  text = input.required<string>();

  // publics
  colorVal = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const color: string = this.color() || "";
    const opacity: TCorOpacities = this.opacity();
    return !!color
      ? hslStrToRgba(cssVar(`--clr-${color}`), opacity / 100)
      : "transparent";
  });
  /** Unique id to avoid collisions when multiple instances exists */
  readonly pathId = computed(
    () =>
      `cp-${Math.abs(
        this.text()
          .split("")
          .reduce((a, c) => a + c.charCodeAt(0), 0),
      )}-${this.sizePx()}`,
  );

  readonly viewBox = computed(() => `0 0 ${this.sizePx()} ${this.sizePx()}`);

  /** Radius = half size minus a small inset so text stays inside */
  readonly radius = computed(() => this.sizePx() / 2 - this.fontSizePx() * 0.8);

  /** SVG circle path — two semicircles so start !== end (SVG arc limitation) */
  readonly circlePath = computed(() => {
    const cx = this.sizePx() / 2;
    const cy = this.sizePx() / 2;
    const r = this.radius();
    return `M ${cx},${cy - r} A ${r},${r} 0 1 1 ${cx},${cy + r} A ${r},${r} 0 1 1 ${cx},${cy - r}`;
  });

  readonly repeatedText = computed(() => {
    const text = this.text();
    const sep = this.separator();
    const r = this.radius();
    const circ = 2 * Math.PI * r;

    // Approximate character width from fontSize + letterSpacing
    const charWidth = this.fontSizePx() * 0.6 + this.letterSpacingPx();
    const singleW = text.length * charWidth;
    const count = singleW > 0 ? Math.max(1, Math.ceil(circ / singleW)) : 1;

    return Array(count).fill(text).join(sep) + sep;
  });

  readonly startOffset = computed(() => "0%");

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    effect(() => {
      const el = this.svgEl()?.nativeElement;
      if (!el) return;
      el.style.setProperty("--spin-duration", `${this.duration()}s`);
      el.style.animationDirection = !this.clockwise() ? "reverse" : "normal";
    });
  }
}

