      ? hslStrToRgba(cssVar(`--clr-${colorInfoBg}`), opacityInfoBg / 100)
      : "transparent";
    const colorInfoBorderTopVal: string = !!colorInfoBorderTop
      ? cssVar(`--clr-${colorInfoBorderTop}`)
      : "transparent";
    const colorInfoTextVal: string = !!colorInfoText
      ? cssVar(`--clr-${colorInfoText}`)
      : "transparent";
    const gapVal: number = COR_BS_SPACINGS?.[gap];
    const paddingInfoXVal: number = COR_PADDINGS?.[paddingInfoX];
    const paddingInfoYVal: number = COR_PADDINGS?.[paddingInfoY];
    const roundedVal: number = COR_ROUNDEDS?.[rounded];
    const shadowVal: string = COR_BOX_SHADOWS?.[shadow];
    const sizeBorderVal: number = COR_BORDER_SIZES?.[sizeBorder];
    const sizeFontCaptionVal: number = COR_FONT_SIZES?.[sizeFontCaption];
    const sizeFontDescriptionVal: number =
