    return `
--cor-expandable-panels-gap: ${gapVal}rem;
--cor-expandable-panels-opacity-extras: ${opacityExtras};
--cor-expandable-panels-opacity-description: ${opacityDescription};
--cor-expandable-panels-opacity-img-collapsed: ${opacityImgCollapsed};
--cor-expandable-panels-bold-caption: ${boldCaptionVal};
--cor-expandable-panels-bold-description: ${boldDescriptionVal};
