  minDecimalDigits = input<number>(COR_FLIP_COUNTER_DEFAULT.minDecimalDigits);
  minIntegerDigits = input<number>(COR_FLIP_COUNTER_DEFAULT.minIntegerDigits);
  roundedCard = input<TCorRoundeds>(COR_FLIP_COUNTER_DEFAULT.roundedCard);
  scrambleCaption = input(COR_FLIP_COUNTER_DEFAULT.scrambleCaption, {
