    // console.log({ ufsProps });

    let hovers: string = "";
    Object.entries(ufsProps).forEach(
      ([sigla, props]) =>
        (hovers += ` --cor-mapa-brasil-clr-bg-uf-hover-${sigla}: ${props.colorBgUfHover};\n`),
