      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBgUfHover();
    const colorTextUf: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorTextUf();

    const colorBgDefVal: string = !!colorBgUf
      ? cssVar(`--clr-${colorBgUf}`)
      : "transparent";
    const colorBgDefHoverVal: string = !!colorBgUfHover
      ? cssVar(`--clr-${colorBgUfHover}`)
      : "transparent";
    const colorTextDefVal: string = !!colorTextUf
      ? cssVar(`--clr-${colorTextUf}`)
      : "transparent";

