          const colorTextUfVal: string = !!ufs[uf]?.colorTextUf
            ? cssVar(`--clr-${ufs[uf]?.colorTextUf}`)
            : "";

          acc[uf] = {
            off: ufs[uf]?.off || off,
            colorBgUf: colorBgUfVal || colorBgDefVal,
            colorBgUfHover: colorBgUfHoverVal || colorBgDefHoverVal,
            colorTextUf: colorTextUfVal || colorTextDefVal,
          };
          return acc;
        },
        {} as Record<TCorUf, ICorMapaBrasilUfProps>,
      );
    // console.log({ ufsProps });

    return ufsProps;
  });

  // publics
  // selected = signal<string | null>(null);
  svgViewBox = computed(() => {
    const v = this.viewBoxSignal();
    return `${v.x} ${v.y} ${v.w} ${v.h}`;
  });

  // privates
  /** Animated viewBox */
  /** Original SVG viewBox (full map) */
  #baseViewBox = {
    x: 0,
    y: 0,
    w: 460,
    h: 460,
  };
  private viewBoxSignal = signal(this.#baseViewBox);
  #animationFrameId: number | null = null;
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    inject(DestroyRef).onDestroy(() => {
      if (this.#animationFrameId !== null) {
        cancelAnimationFrame(this.#animationFrameId);
      }
    });

    effect(() => {
      const zoomIn = this.zoomIn(); // rastreado
      const uf = this.uf(); // rastreado

      // Se zoomIn estiver DESLIGADO: nunca faz zoom por UF, nunca anima por UF
      if (!zoomIn) {
        // cancela animação e garante mapa inteiro
        if (this.#animationFrameId !== null) {
          cancelAnimationFrame(this.#animationFrameId);
          this.#animationFrameId = null;
        }
        this.viewBoxSignal.set(this.#baseViewBox);
        return;
      }

      // Se zoomIn estiver LIGADO: aplica zoom/centralização por UF (com animação)
      untracked(() => {
        if (!uf) {
          this.#animateViewBox(this.#baseViewBox);
          return;
        }

        const path = this.svgRef.nativeElement.querySelector(
          `a.${uf} path`,
        ) as SVGGraphicsElement | null;

        if (!path) return;

        const box = path.getBBox();
        const padding = 20;

        this.#animateViewBox({
          x: box.x - padding,
          y: box.y - padding,
          w: box.width + padding * 2,
          h: box.height + padding * 2,
        });
      });
    });
  }

  // functions
  #animateViewBox(target: { x: number; y: number; w: number; h: number }) {
    // Cancela qualquer animação em andamento
    if (this.#animationFrameId !== null) {
      cancelAnimationFrame(this.#animationFrameId);
      this.#animationFrameId = null;
    }

    const start = { ...this.viewBoxSignal() }; // snapshot imutável do estado atual
    const duration = 300;
    const startTime = performance.now();

    const easeOut = (t: number) => 1 - Math.pow(1 - t, 3);

    const frame = (now: number) => {
      const progress = Math.min((now - startTime) / duration, 1);
      const e = easeOut(progress);

      this.viewBoxSignal.set({
        x: start.x + (target.x - start.x) * e,
        y: start.y + (target.y - start.y) * e,
        w: start.w + (target.w - start.w) * e,
        h: start.h + (target.h - start.h) * e,
      });

      if (progress < 1) {
        this.#animationFrameId = requestAnimationFrame(frame);
      } else {
        this.#animationFrameId = null;
      }
    };

    this.#animationFrameId = requestAnimationFrame(frame);
  }

  // methods
  onUfClick(uf: TCorUf | null) {
    this.select$.emit(this.uf() === uf ? null : uf);
  }
}

