    const boldVal: number = COR_FONT_WEIGHTS?.[bold];
    const boldActiveVal: number = COR_FONT_WEIGHTS?.[boldActive];
    const colorBtnBgVal: string = !!colorBtnBg
      ? cssVar(`--clr-${colorBtnBg}`)
      : "transparent";
    const colorBtnBgActiveVal: string = !!colorBtnBgActive
      ? cssVar(`--clr-${colorBtnBgActive}`)
      : "transparent";
    const colorBtnBgHoverVal: string = !!colorBtnBgHover
      ? cssVar(`--clr-${colorBtnBgHover}`)
      : "transparent";
    const colorBtnBorderVal: string = !!colorBtnBorder
      ? cssVar(`--clr-${colorBtnBorder}`)
      : "transparent";
    const colorBtnBorderActiveVal: string = !!colorBtnBorderActive
      ? cssVar(`--clr-${colorBtnBorderActive}`)
      : "transparent";
    const colorBtnBorderHoverVal: string = !!colorBtnBorderHover
      ? cssVar(`--clr-${colorBtnBorderHover}`)
      : "transparent";
    const colorBtnTextVal: string = !!colorBtnText
      ? cssVar(`--clr-${colorBtnText}`)
      : "transparent";
    const colorBtnTextActiveVal: string = !!colorBtnTextActive
      ? cssVar(`--clr-${colorBtnTextActive}`)
      : "transparent";
    const colorBtnTextHoverVal: string = !!colorBtnTextHover
      ? cssVar(`--clr-${colorBtnTextHover}`)
      : "transparent";
    const paddingXVal: number = COR_PADDINGS?.[paddingX];
    const paddingYVal: number = COR_PADDINGS?.[paddingY];
    const roundedVal: number = COR_ROUNDEDS?.[rounded];
    const sizeBorderVal: number = COR_BORDER_SIZES?.[sizeBorder];
    const sizeFontVal: number = COR_FONT_SIZES?.[sizeFont];
    const sizeFontActiveVal: number = COR_FONT_SIZES?.[sizeFontActive];

    return `
      --cor-pagination-bold: ${boldVal};
      --cor-pagination-bold-active: ${boldActiveVal};
      --cor-pagination-clr-btn-bg: ${colorBtnBgVal};
      --cor-pagination-clr-btn-bg-active: ${colorBtnBgActiveVal};
      --cor-pagination-clr-btn-bg-hover: ${colorBtnBgHoverVal};
      --cor-pagination-clr-btn-border-active: ${colorBtnBorderActiveVal};
      --cor-pagination-clr-btn-border-hover: ${colorBtnBorderHoverVal};
      --cor-pagination-clr-btn-border: ${colorBtnBorderVal};
      --cor-pagination-clr-btn-text: ${colorBtnTextVal};
      --cor-pagination-clr-btn-text-active: ${colorBtnTextActiveVal};
      --cor-pagination-clr-btn-text-hover: ${colorBtnTextHoverVal};
      --cor-pagination-padding-x: ${paddingXVal}rem;
      --cor-pagination-padding-y: ${paddingYVal}rem;
      --cor-pagination-rounded-btn: ${roundedVal}rem;
      --cor-pagination-size-border: ${sizeBorderVal}px;
      --cor-pagination-size-font: ${sizeFontVal}rem;
      --cor-pagination-size-font-active: ${sizeFontActiveVal}rem;
  `
      .trim()
      .replace("\n", "");
  });

  // publics
  hoveredIndex = signal<number>(-1);
  atFirst = signal<boolean>(false);
  atLast = signal<boolean>(false);
  ellipsis = signal<number>(-1).asReadonly();
  page = signal(1);
  itemsPerPage = signal(10);
  totalPages = computed(() =>
    Math.max(1, Math.ceil(this.totalItems() / this.itemsPerPage())),
  );
  rangeStart = computed<number>(
    () => (this.page() - 1) * this.itemsPerPage() + 1,
  );
  rangeEnd = computed<number>(() =>
    Math.min(this.page() * this.itemsPerPage(), this.totalItems()),
  );
  pages = computed<ICorPaginationPageInfo[]>(() => {
    const isMobile = !!this.isMobile();
    return this.#buildPages(!!isMobile ? 0 : 1);
  });
  indicator = signal({
    left: 0,
    width: 0,
    height: 0,
    top: 0,
  });
  numButtons = computed<number>(() => {
    const pages: ICorPaginationPageInfo[] = this.pages() || [];
    return (
      pages.filter((p: ICorPaginationPageInfo) => p?.nroPage >= 0)?.length + 4
    );
  });

  // publics - models
  corBaseColorIdsModel = signal<string>(
    "TCorBaseColorIds: " + Object.values(COR_BASE_COLOR_IDS).toString(),
  ).asReadonly();
  corBsSpacingsModel = signal<string>(
    "TCorBsSpacings: " + Object.keys(COR_BS_SPACINGS).toString(),
  ).asReadonly();
  corCtaColorIdsModel = signal<string>(
    "TCorCtaColorIds: " + Object.values(COR_CTA_COLOR_IDS).toString(),
  ).asReadonly();
  corFontSizesModel = signal<string>(
    "TCorFontSizes: " + Object.keys(COR_FONT_SIZES).toString(),
  ).asReadonly();
  corFontWeightsModel = signal<string>(
    "TCorFontWeights: " + Object.keys(COR_FONT_WEIGHTS).toString(),
  ).asReadonly();
  corRoundedsModel = signal<string>(
    "TCorRoundeds: " + Object.keys(COR_ROUNDEDS).toString(),
  ).asReadonly();
  corSpacingsModel = signal<string>(
    'Exclude<TCorSpacings, "auto">: ' + Object.keys(COR_SPACINGS).toString(),
  ).asReadonly();
  corThemesIdsModel = signal<string>(
    "TCorThemesIds: " + Object.values(COR_THEMES_IDS).toString(),
  ).asReadonly();

  // privates
  #firstTime: boolean = true;
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);
  #injector = inject(Injector);

  // constructor
  constructor() {
    effect(() => {
      if (this.#firstTime) {
        const page: number = this.initialPage();
        const itemsPerPage: number = this.initialItemsPerPage();
        // console.log({ page, itemsPerPage });
        this.page.set(page);
        this.itemsPerPage.set(itemsPerPage);
      }
      this.#firstTime = false;
    });

    effect(() => {
      const page: number = this.page();
      const itemsPerPage: number = this.itemsPerPage();
      const totalItems: number = this.totalItems();
      const totalPages: number = this.totalPages();
      const rangeStart: number = this.rangeStart();
      const rangeEnd: number = this.rangeEnd();
      this.#emit();
    });

    effect(() => {
      const itemsPerPage: number = untracked(() => this.itemsPerPage());
      const totalItems: number = this.totalItems();
      this.onSizeChange(itemsPerPage);
    });

    afterNextRender(
      () => {
        this.#updateIndicator(0);
      },
      { injector: this.#injector },
    );

    effect(() => {
      const index: number = this.hoveredIndex(); // this.openNavIndex();
      // const sizeBorder: TCorBorderSizes = this.sizeBorder(); // this.openNavIndex();
      // console.log({ index }, this.page());
      index >= 0 &&
        /* index !== this.page() + 1 && */ this.#updateIndicator(index);
    });
  }

  // functions
  #updateIndicator(index: number) {
    const el = this.btnsRef?.get(index)?.nativeElement;
    // console.log({ el });
    if (!el) {
      return;
    }

    const sizeBorder: TCorBorderSizes = this.sizeBorder(); // this.openNavIndex();
    const sizeBorderVal: number = COR_BORDER_SIZES?.[sizeBorder];
    // console.log({ sizeBorder, sizeBorderVal });

    const { offsetLeft, offsetTop, clientWidth, clientHeight } = el;
    // console.log({ offsetLeft, offsetTop, clientWidth, clientHeight });

    this.indicator.set({
      left: offsetLeft + sizeBorderVal,
      top: offsetTop + sizeBorderVal,
      width: clientWidth,
      height: clientHeight,
    });
  }

  #buildPages(delta: number): ICorPaginationPageInfo[] {
    const total = this.totalPages();
    const current = this.page();
    const MAX = delta * 2 + 3;

    if (total <= MAX + 2) {
      const pages: number[] = Array.from({ length: total }, (_, i) => i + 1);
      // console.log(JSON.stringify(pages));
      const result: ICorPaginationPageInfo[] = this.#pages2Info(pages);
      return result;
    } // if

    const pages: number[] = [];
    const left = Math.max(2, current - delta);
    const right = Math.min(total - 1, current + delta);

    pages.push(1);
    if (left > 2) pages.push(this.ellipsis());
    for (let p = left; p <= right; p++) pages.push(p);
    if (right < total - 1) pages.push(this.ellipsis());
    pages.push(total);
    // console.log({ pages });
    return this.#pages2Info(pages);
  }

  #pages2Info(pages: number[]): ICorPaginationPageInfo[] {
    let start = 1;
    const result = pages.map((nroPage: number) => {
      let pos = -1; // <- nunca null

      if (nroPage >= 0) {
        start++;
        pos = start;
      }

      return { nroPage, pos };
    });

    return result || [];
  }

  #emit() {
    this.change$.emit({
      page: this.page(),
      itemsPerPage: this.itemsPerPage(),
      totalItems: this.totalItems(),
      totalPages: this.totalPages(),
      rangeStart: this.rangeStart(),
      rangeEnd: this.rangeEnd(),
    });
  }

  // methods
  goTo(page: number = 0) {
    const clamped = Math.min(Math.max(1, page), this.totalPages());
    if (clamped === this.page()) return;
    this.page.set(clamped);
    this.pagChange$.emit(clamped);
    this.#emit();
  }

  onSizeChange(event: Event | number) {
    // const size = Number((event.target as HTMLSelectElement).value) as TItemsPerPageOption;
    const size =
      typeof event === "number"
        ? event
        : Number((event.target as HTMLSelectElement).value);
    this.itemsPerPage.set(size);
    const max = Math.ceil(this.totalItems() / size);
    let newPage: number = this.page();
    // console.log({ size, max, newPage });
    if (newPage > max) {
      newPage = max;
    }
    this.page.set(newPage);
    this.pagChange$.emit(newPage);
    this.itemsPerPageChange$.emit(size);
    this.#emit();
  }
}

