    //   );
    // });

    // Core debounce: reruns whenever searchTerm, debounceMs, or minLength changes
    effect(() => {
      const value: any = this.searchTerm();
      const delay: number = this.debounceMs();
      const minLen: number = this.minLength();

      // this.isPending.set(true);
      // this.change$.emit(value);
      if (this.#timer) clearTimeout(this.#timer);

