        // this.isPending.set(false);
        this.debouncedValue.set(trimmed);
        // console.log({ trimmed }, trimmed.length, minLen);
        if (trimmed.length >= minLen) {
          this.change$.emit(trimmed);
        } // if
      }, delay);
    });
  }

  // lifecycles
  ngOnDestroy(): void {
    if (!!this.#timer) clearTimeout(this.#timer);
  }

