  navigatedTo$ = output<ICorNavItem>();

  // ── resolved props (config tem menor prioridade que input individual) ────────

  /**
   * Mescla: default → config → input individual.
   * Um input individual só sobrescreve o config quando difere do default,
   * indicando que foi explicitamente fornecido pelo consumidor.
   */
  private resolved = computed<ICorSidenavProps>(() => {
    const cfg = this.config() ?? {};
    const d = COR_SIDENAV_DEFAULT;

    const pick = <K extends keyof ICorSidenavProps>(
      key: K,
      inputVal: ICorSidenavProps[K],
    ): ICorSidenavProps[K] =>
      // Se o input individual ainda está no valor default, o config tem precedência
      inputVal !== d[key] ? inputVal : (cfg[key] ?? d[key]);

    const config: ICorSidenavProps = {
      alwaysOpen: pick("alwaysOpen", this.alwaysOpen()),
      animationIcon: pick("animationIcon", this.animationIcon()),
      animationIconActive: pick(
        "animationIconActive",
        this.animationIconActive(),
      ),
      animationIconFound: pick("animationIconFound", this.animationIconFound()),
      autoBadges: pick("autoBadges", this.autoBadges()),
      boldCaption1: pick("boldCaption1", this.boldCaption1()),
      boldCaption2: pick("boldCaption2", this.boldCaption2()),
      boldCaption3: pick("boldCaption3", this.boldCaption3()),
      boldCaptionFound: pick("boldCaptionFound", this.boldCaptionFound()),
      colorBgActive: pick("colorBgActive", this.colorBgActive()),
      colorBorderBottom: pick("colorBorderBottom", this.colorBorderBottom()),
      colorText: pick("colorText", this.colorText()),
      colorTextActive: pick("colorTextActive", this.colorTextActive()),
      // dark: pick('dark', this.dark()),
      filter: pick("filter", this.filter()),
      gap: pick("gap", this.gap()),
      opacityIcon: pick("opacityIcon", this.opacityIcon()),
      paddingX: pick("paddingX", this.paddingX()),
      paddingY: pick("paddingY", this.paddingY()),
      roundedActive: pick("roundedActive", this.roundedActive()),
      sizeFont: pick("sizeFont", this.sizeFont()),
      sizeIcon: pick("sizeIcon", this.sizeIcon()),
    };
    this.config$.emit(config);

    return config;
  });

  // ── atalhos reativos para o template ────────────────────────────────────────

  protected _alwaysOpen = computed(() => this.resolved().alwaysOpen);
  protected _animationIcon = computed(() => this.resolved().animationIcon);
  protected _animationIconActive = computed(
    () => this.resolved().animationIconActive,
  );
  protected _animationIconFound = computed(
    () => this.resolved().animationIconFound,
  );
  protected _autoBadges = computed(() => this.resolved().autoBadges);
  protected _boldCaption1 = computed(() => this.resolved().boldCaption1);
  protected _boldCaption2 = computed(() => this.resolved().boldCaption2);
  protected _boldCaption3 = computed(() => this.resolved().boldCaption3);
  protected _boldCaptionFound = computed(
    () => this.resolved().boldCaptionFound,
  );
  protected _colorBgActive = computed(() => this.resolved().colorBgActive);
  protected _colorBorderBottom = computed(
    () => this.resolved().colorBorderBottom,
  );
  protected _colorText = computed(() => this.resolved().colorText);
  protected _colorTextActive = computed(() => this.resolved().colorTextActive);
  // protected _dark = computed(() => this.resolved().dark);
  protected _filter = computed(() => this.resolved().filter);
  protected _gap = computed(() => this.resolved().gap);
  protected _opacityIcon = computed(() => this.resolved().opacityIcon);
  protected _paddingX = computed(() => this.resolved().paddingX);
  protected _paddingY = computed(() => this.resolved().paddingY);
  protected _roundedActive = computed(() => this.resolved().roundedActive);
  protected _sizeFont = computed(() => this.resolved().sizeFont);
  protected _sizeIcon = computed(() => this.resolved().sizeIcon);

  // ── signals internos ────────────────────────────────────────────────────────

  hoverId = signal<string | null>(null);
  isNavHovered = signal<boolean>(false);

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // ── computeds públicos ──────────────────────────────────────────────────────

  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const colorBgActiveVal = cssVar(`--clr-${this._colorBgActive()}`);
    const colorTextActiveVal = cssVar(`--clr-${this._colorTextActive()}`);
    const paddingXVal: number = COR_PADDINGS?.[this._paddingX()];
    const paddingYVal: number = COR_PADDINGS?.[this._paddingY()];

    return `
      --cor-sidenav-clr-bg-active: ${colorBgActiveVal};
      --cor-sidenav-clr-text-active: ${colorTextActiveVal};
      --cor-sidenav-padding-x: ${paddingXVal}rem;
      --cor-sidenav-padding-y: ${paddingYVal}rem;
    `
      .trim()
      .replace("\n", "");
  });

  // ── helpers de mapeamento (compartilhados entre itemsAll e itemsFiltered) ────

  private resolveBadge(
    badge: string | undefined,
    hasChildren: boolean,
    countAll: number,
    foundAll: number,
    autoBadges: boolean,
  ): string | undefined {
    if (!hasChildren) {
      return badge;
    }
    if (!autoBadges) {
      return badge;
    }
    const value = foundAll > 0 ? foundAll : countAll;
    return value > 0 ? String(value) : undefined;
  }

  private resolveVisible(
    filter: string,
    isWildcard: boolean,
    matched: boolean,
    hasChildren: boolean,
  ): boolean {
    if (!filter) {
      return true;
    }
    if (isWildcard) {
      return true;
    }
    return matched || hasChildren;
  }

  /**
   * Mapeia recursivamente a árvore de items.
   * @param applyFilter quando `true`, calcula __visible de acordo com o filtro
   *  e remove os filhos não visíveis; quando `false`, __visible é sempre `true`
   *  e todos os filhos são mantidos (itemsAll$).
   */
  private mapTree(
    items: ICorNavItem[],
    filter: string,
    isWildcard: boolean,
    autoBadges: boolean,
    applyFilter: boolean,
  ): ICorNavItem[] {
    const mapItem = (item: ICorNavItem): ICorNavItem => {
      const mappedChildren = (item?.children || []).map(mapItem);
      const children = applyFilter
        ? mappedChildren.filter((i): i is ICorNavItem => !!i?.__visible)
        : mappedChildren;

      const hasChildren = children.length > 0;
      const hasUrl = !!item?.url;

      // __count: apenas folhas (sem filhos) com url definida
      const count = !hasChildren && hasUrl ? 1 : 0;

      // __found: false sem filtro; com filtro, apenas folhas com url cujo caption inclua o filtro
      const found =
        !!filter &&
        !isWildcard &&
        !hasChildren &&
        hasUrl &&
        (item?.caption || "").toLocaleLowerCase().includes(filter);

      // __countAll / __foundAll: soma de __count/__found (+ __countAll/__foundAll) dos filhos
      const countAll = children.reduce(
        (acc, c) => acc + (c.__count ?? 0) + (c.__countAll ?? 0),
        0,
      );
      const foundAll = children.reduce(
        (acc, c) => acc + (c.__found ? 1 : 0) + (c.__foundAll ?? 0),
        0,
      );

      // "matched" usado apenas para visibilidade (considera wildcard e itens com filhos)
      const matched =
        !isWildcard &&
        !!filter &&
        (item?.caption || "").toLocaleLowerCase().includes(filter);

      return {
        ...item,
        badge: this.resolveBadge(
          item?.badge,
          hasChildren,
          countAll,
          foundAll,
          autoBadges,
        ),
        caption: item?.caption || "",
        icon: item?.icon || "icon-empty",
        iconHovered: item?.iconHovered || "",
        off: !!item?.off,
        __open: filter ? foundAll > 0 || found : !!item?.__open,
        __visible: applyFilter
          ? this.resolveVisible(filter, isWildcard, matched, hasChildren)
          : true,
        __count: count,
        __found: found,
        url: item?.url || "",
        children,
        __countAll: countAll,
        __foundAll: foundAll,
      };
    };

    return (items || []).map(mapItem);
  }

  // ── árvores itemsAll / itemsFiltered ─────────────────────────────────────────

  // protected itemsAllTree = computed<ICorNavItem[]>(() => {
  //   const filter = (this._filter() || '').toLocaleLowerCase(); // 👈 usar _filter()
  //   const isWildcard = filter === '*';
  //   const autoBadges = this.resolved().autoBadges;

  //   const items = this.mapTree(this.items(), filter, isWildcard, autoBadges, false);
  //   this.itemsAll$.emit(items);

  //   return items;
  // });

  // protected itemsFilteredTree = computed<ICorNavItem[]>(() => {
  //   const filter = (this._filter() || '').toLocaleLowerCase(); // 👈 usar _filter()
  //   const isWildcard = filter === '*';
  //   const autoBadges = this.resolved().autoBadges;

  //   const items = this.mapTree(this.items(), filter, isWildcard, autoBadges, true);
  //   this.itemsFiltered$.emit(items);

  //   return items;
  // });

  /** Mantido para uso no template: comportamento idêntico ao anterior. */
  protected data = computed<ICorNavItem[]>(() => {
    const filter = (this._filter() || "").toLocaleLowerCase();
    const isWildcard = filter === "*";
    const autoBadges = this.resolved().autoBadges;
    return this.mapTree(
      this.items(),
      filter,
      isWildcard,
      autoBadges,
      true,
    ).filter((i) => !!i?.__visible);
  });

  protected open = computed<boolean>(() => {
    const open =
      !!this.isNavHovered() || !!this._alwaysOpen() || !!this._filter();
    // console.log({ open });
    this.isNavOpen$.emit(open);
    return open;
  });

  // ── injects ─────────────────────────────────────────────────────────────────

  #router = inject(Router);
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // ── constructor ─────────────────────────────────────────────────────────────

  constructor() {
    effect(() => this.isNavHovered$.emit(!!this.isNavHovered()));

    effect(() => {
      const filter = (this._filter() || "").toLocaleLowerCase();
      const isWildcard = filter === "*";
      const autoBadges = this.resolved().autoBadges;

      const itemsAll = this.mapTree(
        this.items(),
        filter,
        isWildcard,
        autoBadges,
        false,
      );
      this.itemsAll$.emit(itemsAll);
    });

    effect(() => {
      const filter = (this._filter() || "").toLocaleLowerCase();
      const isWildcard = filter === "*";
      const autoBadges = this.resolved().autoBadges;

      const itemsFiltered = this.mapTree(
        this.items(),
        filter,
        isWildcard,
        autoBadges,
        true,
      );
      this.itemsFiltered$.emit(itemsFiltered);
    });
  }

  // ── methods ─────────────────────────────────────────────────────────────────
  onItemClick(i: ICorNavItem, event: Event) {
    event.stopPropagation();

    if (!i?.off) {
      if (!!i?.url) {
        this.#router.navigateByUrl(i.url);
        this.isNavHovered.set(false);
        console.log({ i });
        this.navigatedTo$.emit(i);

        if (event) {
          (event.target as HTMLElement).blur();
          this.isNavHovered.set(false);
          this.hoverId.set(null);
        }
      } else {
        i.__open = !i.__open;
      }
    }
  }
}

