@Component({
  selector: "cor-switch",
  imports: [CommonModule],
  templateUrl: "./switch.html",
  styleUrl: "./switch.scss",
})
export class CorSwitchComponent implements FormCheckboxControl {
  // ── FormValueControl API ─────────────────────────────────────────────────
  // `value` é o contrato mínimo exigido pela interface.
  // O Angular observa este model() e sincroniza com formControlName / ngModel
  // automaticamente — sem providers, sem writeValue, sem callbacks manuais.
  readonly checked = model<boolean>(!!COR_SWITCH_DEFAULT.checked);

  // Status opcionais — Angular injeta os valores do FormControl de volta
  readonly disabled = input<boolean>(false);
  readonly touched = input<boolean>(false);
  readonly dirty = input<boolean>(false);
  readonly invalid = input<boolean>(false);
  readonly required = input<boolean>(false);

  // ── inputs de aparência ──────────────────────────────────────────────────
  bold = input<TCorFontWeights>(COR_SWITCH_DEFAULT.bold);
  caption = input<string>(COR_SWITCH_DEFAULT.caption);
  colorActive = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_SWITCH_DEFAULT.colorActive,
  );
  colorBorder = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_SWITCH_DEFAULT.colorBorder,
  );
  colorInactive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_SWITCH_DEFAULT.colorInactive);
  colorText = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_SWITCH_DEFAULT.colorText,
  );
  colorTrack = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_SWITCH_DEFAULT.colorTrack,
  );
  gap = input<TCorBsSpacings>(COR_SWITCH_DEFAULT.gap);
  off = input(COR_SWITCH_DEFAULT.off, { transform: booleanAttribute });
  size = input<TCorSwitchSizes>(COR_SWITCH_DEFAULT.size);
  sizeBorder = input<TCorBorderSizes>(COR_SWITCH_DEFAULT.sizeBorder);
  sizeFont = input<TCorFontSizes>(COR_SWITCH_DEFAULT.sizeFont);

  // outputs
  toggled$ = output<boolean>();

  /** Desabilitado pelo form OU pelo prop `off`. */
  protected isOff = computed(() => this.off() || this.disabled());

  toggle(): void {
    if (this.isOff()) return;
    this.checked.set(!this.checked()); // Angular observa e sincroniza
    this.toggled$.emit(this.checked());
  }

  // ── estilos computados ───────────────────────────────────────────────────
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const colorActive = this.colorActive();
    const colorBorder = this.colorBorder();
    const colorInactive = this.colorInactive();
    const colorTrack = this.colorTrack();
    const sizeBorder = this.sizeBorder();

    const colorActiveVal = colorActive
      ? cssVar(`--clr-${colorActive}`)
      : "transparent";
    const colorBorderVal = colorBorder
      ? cssVar(`--clr-${colorBorder}`)
      : "transparent";
    const colorInactiveVal = colorInactive
      ? cssVar(`--clr-${colorInactive}`)
      : "transparent";
    const colorTrackVal = colorTrack
      ? cssVar(`--clr-${colorTrack}`)
      : "transparent";
    const sizeBorderVal = COR_BORDER_SIZES?.[sizeBorder];

    return `
--cor-switch-clr-active: ${colorActiveVal};
--cor-switch-clr-border: ${colorBorderVal};
--cor-switch-clr-inactive: ${colorInactiveVal};
--cor-switch-clr-track: ${colorTrackVal};
--cor-switch-size-border: ${sizeBorderVal}px;
    `.trim();
  });

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);
}

