  widthFadeRem = input<number>(COR_TEXT_SCROLLER_DEFAULT.widthFadeRem);

  // publics
  readonly isPaused = signal(false);
  readonly direction = computed<TCorAnimationDirections>(() =>
    this.reverse() ? "reverse" : "normal",
  );
  readonly track = viewChild<ElementRef<HTMLDivElement>>("track");

  // publics - styles
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const colorAccent: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorAccent();
    const colorBg: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorBg();
    const colorFade: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorFade();
    const colorText: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorText();
    const duration: number = this.duration();
    const direction: TCorAnimationDirections = this.direction();
    // const opacityFade: TCorOpacities = this.opacityFade();
    const opacitySeparator: TCorOpacities = this.opacitySeparator();
    const paddingX: Exclude<TCorSpacings, "auto"> = this.paddingX();
    const paddingY: Exclude<TCorSpacings, "auto"> = this.paddingY();
    // const shadow: TCorBoxShadows = this.shadow();
    const sizeFont: TCorFontSizes = this.sizeFont();
    const tracking: TCorLetterSpacings = this.tracking();
    const widthFadeRem: number = this.widthFadeRem();

    // vals
    const colorAccentVal: string = !!colorAccent
      ? cssVar(`--clr-${colorAccent}`)
      : "transparent";
    const colorBgVal: string = !!colorBg
      ? cssVar(`--clr-${colorBg}`)
      : "transparent";
    const colorFadeVal: string = !!colorFade
      ? cssVar(`--clr-${colorFade}`)
      : "transparent";
    const colorTextVal: string = !!colorText
      ? cssVar(`--clr-${colorText}`)
      : "transparent";
    const paddingXVal: number = COR_PADDINGS?.[paddingX];
    const paddingYVal: number = COR_PADDINGS?.[paddingY];
    // const shadowVal: string = COR_BOX_SHADOWS?.[shadow];
    const sizeFontVal: number = COR_FONT_SIZES?.[sizeFont];
    const opacitySeparatorVal: number = COR_OPACITIES?.[opacitySeparator];
    const trackingVal: number = COR_LETTER_SPACINGS?.[tracking];
    // console.log({ sizeFontVal, paddingXVal });
    // --cor-text-scroller-shadow: ${shadowVal};

    return `
--cor-text-scroller-clr-accent: ${colorAccentVal};
--cor-text-scroller-clr-bg: ${colorBgVal};
--cor-text-scroller-clr-fade: ${colorFadeVal};
--cor-text-scroller-clr-text: ${colorTextVal};
--cor-text-scroller-duration: ${duration}ms;
--cor-text-scroller-direction: ${direction};
--cor-text-scroller-height: ${sizeFontVal + paddingYVal * 2 + 1}rem;
--cor-text-scroller-letter-spacing: ${trackingVal}em;
--cor-text-scroller-opacity-separator: ${opacitySeparatorVal};
--cor-text-scroller-padding-x: ${paddingXVal}rem;
--cor-text-scroller-width-fade: ${widthFadeRem}rem;
    `
      .trim()
      .replace("\n", "");
  });

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    effect(() => {
      if (!this.off()) {
        this.isPaused.set(false);
      } else {
        this.isPaused.set(true); // or: this.isPaused.set(this.off())
      }
    });
  }

  // methods
  onMouseEnter() {
    if (this.pauseOnHover()) this.isPaused.set(true);
  }
  onMouseLeave() {
    if (this.pauseOnHover()) this.isPaused.set(false);
  }
  ngOnDestroy() {
    this.isPaused.set(false);
  }
}

export interface ICorTypewriterProps {
  bold: TCorFontWeights;
  colorText: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  delay: number;
  eraseSpeed: number;
  loop: boolean;
  pauseAfterErase: number;
  pauseAfterType: number;
  sizeFont: TCorFontSizes;
  speed: number;
  texts: string[];
  tracking: TCorLetterSpacings;
  transition: TCorTypewriterTransitions;
}

// 'I build with Angular signals.\nI type letter by letter.\nI loop through multiple strings.\nI am a typewriter.'

@Component({
  selector: "cor-typewriter",
  imports: [
    // modules
    CommonModule,
  ],
  templateUrl: "./typewriter.html",
  styleUrl: "./typewriter.scss",
})
export class CorTypewriterComponent {
  // inputs
  bold = input<TCorFontWeights>(COR_TYPEWRITER_DEFAULT.bold);
  colorText = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_TYPEWRITER_DEFAULT.colorText,
  );
  delay = input<number>(COR_TYPEWRITER_DEFAULT.delay); // Initial delay in ms before the first character is typed.
  eraseSpeed = input<number>(COR_TYPEWRITER_DEFAULT.eraseSpeed); // Characters erased per second (used when transition = 'erase').
  loop = input(COR_TYPEWRITER_DEFAULT.loop, { transform: booleanAttribute }); // Loop through the array indefinitely.
  pauseAfterErase = input<number>(COR_TYPEWRITER_DEFAULT.pauseAfterErase); // Pause in ms after erasing / clearing, before typing the next string.
  pauseAfterType = input<number>(COR_TYPEWRITER_DEFAULT.pauseAfterType); // Pause in ms after fully typing a string, before erasing / moving on.
  sizeFont = input<TCorFontSizes>(COR_TYPEWRITER_DEFAULT.sizeFont);
  speed = input<number>(COR_TYPEWRITER_DEFAULT.speed);
  texts = input.required<string[]>();
  tracking = input<TCorLetterSpacings>(COR_TYPEWRITER_DEFAULT.tracking);
  transition = input<TCorTypewriterTransitions>(
    COR_TYPEWRITER_DEFAULT.transition,
  );

  // publics
  displayed = signal("");
  isIdle = signal(false);

  // privates
  #accumulated = "";
  #charIndex = 0;
  #stringIndex = 0;
  #timerId: ReturnType<typeof setTimeout> | null = null;

  // constructor
  constructor() {
    effect(() => {
      // Read all inputs so the effect re-runs when any changes
      const texts: string[] = this.texts();
      const delay: number = this.delay();
      void this.speed();
      void this.eraseSpeed();
      void this.pauseAfterType();
      void this.pauseAfterErase();
      void this.transition();
      void this.loop();

      this.#hardReset();
      this.#timerId = setTimeout(() => this.#typeNext(), delay);
    });
  }

  // lifecycles
  ngOnDestroy(): void {
    this.#hardReset();
  }

  // functions
  private get strings(): string[] {
    const t = this.texts();
    return Array.isArray(t) ? t : [t];
  }

  #currentString(): string {
    return this.strings[this.#stringIndex] ?? "";
  }

  #hardReset(): void {
    if (this.#timerId !== null) {
      clearTimeout(this.#timerId);
      this.#timerId = null;
    }
    this.#stringIndex = 0;
    this.#charIndex = 0;
    this.#accumulated = "";
    this.displayed.set("");
    this.isIdle.set(false);
  }

  #schedule(fn: () => void, ms: number): void {
    this.#timerId = setTimeout(fn, ms);
  }

  // functions: Type / Erase machine
  #typeNext(): void {
    this.#charIndex = 0;
    this.isIdle.set(false);
    this.#typeTick();
  }

  #typeTick(): void {
    const str = this.#currentString();
    const interval = 1000 / Math.max(this.speed(), 1);

    if (this.#charIndex <= str.length) {
      this.displayed.set(this.#accumulated + str.slice(0, this.#charIndex++));
      this.#schedule(() => this.#typeTick(), interval);
    } else {
      this.#onTypingDone();
    }
  }

  #onTypingDone(): void {
    const strings = this.strings;
    const isLast = this.#stringIndex === strings.length - 1;

    if (strings.length === 1 || (isLast && !this.loop())) {
      this.isIdle.set(true); // nothing more to do
      return;
    }

    this.isIdle.set(true);
    this.#schedule(() => this.#beginTransition(), this.pauseAfterType());
  }

  #beginTransition(): void {
    switch (this.transition()) {
      case "erase":
        this.#eraseTick();
        break;

      case "clear":
        this.displayed.set(this.#accumulated);
        this.#advanceString();
        this.#schedule(() => this.#typeNext(), this.pauseAfterErase());
        break;

      case "replace":
        this.#advanceString();
        this.#typeNext();
        break;

      case "append":
        this.#accumulated = this.displayed() + "\n";
        this.#advanceString();
        this.#schedule(() => this.#typeNext(), this.pauseAfterErase());
        break;
    }
  }

  #eraseTick(): void {
    const interval = 1000 / Math.max(this.eraseSpeed(), 1);
    const visible = this.displayed().slice(this.#accumulated.length);

    if (visible.length > 0) {
      this.displayed.set(this.#accumulated + visible.slice(0, -1));
      this.#schedule(() => this.#eraseTick(), interval);
    } else {
      this.#advanceString();
      this.#schedule(() => this.#typeNext(), this.pauseAfterErase());
    }
  }

  #advanceString(): void {
    this.#stringIndex = (this.#stringIndex + 1) % this.strings.length;
  }
}
